{{
(() => {

  const selectedDept = appsmith.store.selectedDepartment?.trim().toLowerCase();
  const rows = GetDepartmentSignOff.data || [];

  if (!selectedDept || !rows.length) return "Not signed off";

  const data = rows.find(r =>
    r.Department?.trim().toLowerCase() === selectedDept
  );

  if (!data) return "Not signed off";

  const signed = Number(data.SignedOff) === 1;

  if (signed) {
    return "Approved by " + data.HeadOfDeptName +
           " on " + moment(data.SignedDate).format("DD/MM/YYYY HH:mm");
  }

  return "Not approved";

})()
}}
